// === CONFIG ===
const TZ = 'America/Sao_Paulo';
const SLOT_MIN = 60; // duração do compromisso em minutos

// === Utils de data/time ===
function toSPDate(d) {
  return new Date(new Date(d).toLocaleString('en-US', { timeZone: TZ }));
}

function parseDataHora(raw) {
  if (!raw) return null;
  if (typeof raw !== 'string') return new Date(raw);
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) {
    return new Date(raw + 'T12:00:00-03:00');
  }
  return new Date(raw);
}

function fmtISOOffset(d) {
  const pad = (n) => String(n).padStart(2,'0');
  const offMin = -d.getTimezoneOffset();
  const sign = offMin >= 0 ? '+' : '-';
  const hh = pad(Math.floor(Math.abs(offMin)/60));
  const mm = pad(Math.abs(offMin)%60);
  return (
    d.getFullYear() + '-' +
    pad(d.getMonth()+1) + '-' +
    pad(d.getDate()) + 'T' +
    pad(d.getHours()) + ':' +
    pad(d.getMinutes()) + ':' +
    pad(d.getSeconds()) +
    sign + hh + ':' + mm
  );
}

function dayKeyJS(date) {
  const keys = ['sun','mon','tue','wed','thu','fri','sat'];
  return keys[ date.getDay() ];
}

function getWorkWindowForDay(agenda, key) {
  const works = agenda[`${key}_works`];
  const start = agenda[`${key}_start`];
  const end   = agenda[`${key}_end`];
  return { works, start, end };
}

function buildDateAtTime(baseLocalDate, timeHHMMSS) {
  const [hh, mm, ss] = (timeHHMMSS || '00:00:00').split(':').map(Number);
  const d = toSPDate(baseLocalDate);
  d.setHours(hh, mm, (Number.isFinite(ss) ? ss : 0), 0);
  return d;
}

function diaSemanaPt(date) {
  return new Intl.DateTimeFormat('pt-BR', { weekday: 'long', timeZone: TZ }).format(date);
}

function timeHHMMSS(date) {
  const pad = (n) => String(n).padStart(2, '0');
  return `${pad(date.getHours())}:${pad(date.getMinutes())}:${pad(date.getSeconds())}`;
}

// === Coleta agendas do input ===
const agendas = $input.all().map(i => i.json);

// === Webhook data ===
const wb = (() => {
  try { return $('Webhook').first().json.body || {}; } catch { return {}; }
})();

const dataHoraStr = wb.data_e_hora;
const funcionarioReqRaw = wb.funcionario;
const dataOriginalStr = wb.data_original || null;

const assignedFromItemRaw = $json?.assigned_user_id;

const funcionarioId = funcionarioReqRaw ? String(funcionarioReqRaw).trim() : null;
const assignedFromItem = assignedFromItemRaw ? String(assignedFromItemRaw).trim() : null;

// === Seleção do corretor alvo (STRICT) ===
let alvo = null;

if (funcionarioId) {
  const funcionarioLc = funcionarioId.toLowerCase();
  alvo =
    agendas.find(a => a.assigned_user_id === funcionarioId) ||
    agendas.find(a => a.calendar_id === funcionarioId) ||
    agendas.find(a => (a.calendar_name || '').toLowerCase() === funcionarioLc) ||
    null;

  if (!alvo) {
    return [{
      json: {
        ok: false,
        motivo: 'Corretor solicitado (Webhook.body.funcionario) não encontrado entre as agendas carregadas.',
        solicitado: funcionarioId
      }
    }];
  }
} else if (assignedFromItem) {
  alvo = agendas.find(a => a.assigned_user_id === assignedFromItem) || null;
  if (!alvo) {
    return [{
      json: {
        ok: false,
        motivo: 'assigned_user_id do item não corresponde a nenhuma agenda.',
        solicitado: assignedFromItem
      }
    }];
  }
} else if (agendas.length === 1) {
  alvo = agendas[0];
} else {
  return [{
    json: {
      ok: false,
      motivo: 'Ambiguidade: múltiplas agendas e nenhum identificador (funcionario/assigned_user_id) fornecido.'
    }
  }];
}

// === Parse do horário solicitado ===
const requestedStartRaw = parseDataHora(dataHoraStr);
if (!requestedStartRaw || isNaN(requestedStartRaw.getTime())) {
  return [{
    json: {
      ok: false,
      motivo: 'data_e_hora inválida ou ausente no Webhook.',
      recebido: dataHoraStr ?? null
    }
  }];
}

const requestedStart = toSPDate(requestedStartRaw);
const requestedEnd   = new Date(requestedStart.getTime() + SLOT_MIN*60000);

// === Data original com hora ===
let dataOriginalObj = null;
if (dataOriginalStr) {
  const dataOriginalStart = toSPDate(parseDataHora(dataOriginalStr));
  const dataOriginalEnd   = new Date(dataOriginalStart.getTime() + SLOT_MIN*60000);
  dataOriginalObj = {
    data_inicio_original: fmtISOOffset(dataOriginalStart),
    data_final_original: fmtISOOffset(dataOriginalEnd)
  };
}

// === Janela de trabalho do dia ===
const dkey = dayKeyJS(requestedStart);
const { works, start, end } = getWorkWindowForDay(alvo, dkey);

if (!works) {
  return [{
    json: {
      ok: false,
      disponivel: false,
      motivo: 'Fora do dia/escala: não trabalha neste dia.',
      corretor: {
        assigned_user_id: alvo.assigned_user_id,
        calendar_name: alvo.calendar_name,
        calendar_id: alvo.calendar_id,
      },
      solicitado: {
        inicio: fmtISOOffset(requestedStart),
        fim: fmtISOOffset(requestedEnd),
        slot_min: SLOT_MIN
      },
      expediente: { trabalha: works, inicio: start, fim: end },
      dia_semana: diaSemanaPt(requestedStart),
      horario_solicitado: timeHHMMSS(requestedStart),
      data_original: dataOriginalObj
    }
  }];
}

const expIni = buildDateAtTime(requestedStart, start);
const expFim = buildDateAtTime(requestedStart, end);

const dentroExpediente =
  requestedStart.getTime() >= expIni.getTime() &&
  requestedEnd.getTime()   <= expFim.getTime();

const disponivel = dentroExpediente;

return [{
  json: {
    ok: true,
    disponivel,
    motivo: disponivel ? 'Dentro do expediente.' : 'Fora do expediente para o slot solicitado.',
    corretor: {
      assigned_user_id: alvo.assigned_user_id,
      calendar_name: alvo.calendar_name,
      calendar_id: alvo.calendar_id,
    },
    solicitado: {
      inicio: fmtISOOffset(requestedStart),
      fim: fmtISOOffset(requestedEnd),
      slot_min: SLOT_MIN
    },
    expediente: {
      trabalha: works,
      inicio: start,
      fim: end,
      inicio_local: fmtISOOffset(expIni),
      fim_local: fmtISOOffset(expFim)
    },
    dia_semana: diaSemanaPt(requestedStart),
    horario_solicitado: timeHHMMSS(requestedStart),
    data_original: dataOriginalObj
  }
}];

const payload = $('Update an event').first().json;

// === Utils para formatar data em PT-BR ===
function formatarDataHora(dateStr) {
  const data = new Date(dateStr);
  return data.toLocaleDateString('pt-BR', {
    day: '2-digit',
    month: 'long',
    year: 'numeric',
    timeZone: 'America/Sao_Paulo'
  }) + ' às ' + data.toLocaleTimeString('pt-BR', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'America/Sao_Paulo'
  });
}

// === Pega o número do imóvel do summary ===
function extrairImovel(summary) {
  const match = summary.match(/\d+/);
  return match ? match[0] : null;
}

const dataFormatada = formatarDataHora(payload.start.dateTime);
const imovel = extrairImovel(payload.summary);

return [
  {
    json: {
      resposta: `Visita agendada para ${dataFormatada} no imóvel ${imovel}`
    }
  }
];

