const dataEntrada = toSP(dataEntradaStr);
const diaBase = toSP(dataEntradaStr);
diaBase.setHours(12,0,0,0);

// Plantão
let plantaoStart, plantaoEnd;
if (row.start && row.end) {
  plantaoStart = toSP(row.start);
  plantaoEnd   = toSP(row.end);
} else {
  const { works, start, end } = getWeekParts(row, dataEntrada);
  if (!works || !start || !end) return [];
  plantaoStart = withTime(diaBase, start);
  plantaoEnd   = withTime(diaBase, end);
}

