const offsets = [-2, -1, +1, +2];
const candidatos = offsets.map(off => {
  const s = new Date(dataEntrada);
  s.setHours(s.getHours() + off, 0, 0, 0);
  const e = new Date(s); e.setHours(e.getHours() + 1);
  return { s, e };
});

