  ? `Infelizmente no horário ${horarioSolicitado} não tenho disponibilidade.`
  : `Infelizmente não tenho disponibilidade exatamente no horário solicitado.`;

let mensagem;
if (horariosDisponiveis.length > 0) {
  const lista = horariosDisponiveis.map(h => `• ${h}`).join('\n');
  mensagem = `${prefixo}\n\nPorém tenho disponibilidade nestes horários:\n${lista}\n\nMe diga qual você prefere que eu já agendo pra você.`;
} else {
  mensagem = `${prefixo}\n\nNo momento não há outras opções disponíveis. Quer que eu verifique outros dias ou turnos?`;
}

// Retorna um único item com a mensagem e a lista de horários
return [
  {
    json: {
      mensagem,
      horarios_disponiveis: horariosDisponiveis
    }
  }
];

// === CONFIG ===
const SLOT_MIN = 60;            // duração do slot em minutos
const FIXED_OFFSET = '-03:00';  // SP (sem horário de verão)

// === HELPERS ===
function pad2(n){ return String(n).padStart(2,'0'); }

function parseLocalSP(datetimeStr){
  if (!datetimeStr || typeof datetimeStr !== 'string') return null;
  const s = datetimeStr.replace(/([+-]\d{2}:\d{2}|Z)$/,''); // remove TZ/Z
  const [datePart, timePartRaw] = s.split('T');
  if (!datePart || !timePartRaw) return null;
  const timePart = timePartRaw.length === 5 ? timePartRaw + ':00' : timePartRaw;
  const [Y, M, D] = datePart.split('-').map(Number);
  const [h, m, sec] = timePart.split(':').map(Number);

  const dow = new Date(Date.UTC(Y, (M-1), D)).getUTCDay(); // 0 dom ... 6 sáb
  const minutes = (h*60) + m;

  return { Y, M, D, h, m, sec: (sec||0), dow, minutes };
}

function addMinutesToHM(h, m, delta){
  const total = h*60 + m + delta;
  return { h: Math.floor(total/60), m: total % 60 };
}

function hmToMinutes(hms){
  if (!hms) return null;
  const [h,m] = hms.split(':').map(Number);
  return (h||0)*60 + (m||0);
}

function mapDay(dow){
  return [
    { works:'sun_works', start:'sun_start', end:'sun_end' },
    { works:'mon_works', start:'mon_start', end:'mon_end' },
    { works:'tue_works', start:'tue_start', end:'tue_end' },
    { works:'wed_works', start:'wed_start', end:'wed_end' },
    { works:'thu_works', start:'thu_start', end:'thu_end' },
    { works:'fri_works', start:'fri_start', end:'fri_end' },
    { works:'sat_works', start:'sat_start', end:'sat_end' },
  ][dow];
}

function buildISO(Y,M,D,h,m,sec=0){
  return `${Y}-${pad2(M)}-${pad2(D)}T${pad2(h)}:${pad2(m)}:${pad2(sec)}${FIXED_OFFSET}`;
}

function shuffle(arr){
  return arr
    .map(v => ({ v, r: Math.random() }))
    .sort((a,b) => a.r - b.r)
    .map(o => o.v);
}

