const parsed = parseLocalSP(solicitadoRaw);
if (!parsed){
  return [{ json: { ok:false, motivo:'data_e_hora inválido/ausente', recebido: solicitadoRaw }}];
}

const dm = mapDay(parsed.dow);
if (!dm){
  return [{ json: { ok:false, motivo:'Dia da semana inválido', data_e_hora: solicitadoRaw }}];
}

const startMinutes = parsed.minutes;
const endMinutes   = startMinutes + SLOT_MIN;

// Monta início/fim ISO do "horário solicitado"
const currentInicioISO = buildISO(parsed.Y, parsed.M, parsed.D, parsed.h, parsed.m, parsed.sec);
const currentFimHM = addMinutesToHM(parsed.h, parsed.m, SLOT_MIN);
const currentFimISO = buildISO(parsed.Y, parsed.M, parsed.D, currentFimHM.h, currentFimHM.m, parsed.sec);

// === LOCALIZA CORRETOR ATUAL (SEM VALIDAR EXPEDIENTE) ===
let atualCalendarId = null;
let atualCalendarName = null;
let atualAssignedId = funcionarioId || idFromInput || null;

if (atualAssignedId) {
  const atual = (agendas || []).find(a => a.assigned_user_id === atualAssignedId);
  if (atual) {
    atualCalendarId = atual.calendar_id || null;
    atualCalendarName = atual.calendar_name || null;
  }
}

