for (const cal of (agendas || [])) {
  if (!cal) continue;

  // Exclui o próprio corretor atual e (opcionalmente) o assigned do item atual
  if (atualAssignedId && cal.assigned_user_id === atualAssignedId) continue;
  if (currentAssignedFromItem && cal.assigned_user_id === currentAssignedFromItem) continue;

  // Trabalha nesse dia?
  if (!cal[dm.works]) continue;

  const workStart = hmToMinutes(cal[dm.start]);
  const workEnd   = hmToMinutes(cal[dm.end]);
  if (workStart == null || workEnd == null) continue;

  // Cabe o slot dentro do expediente?
  const fits = startMinutes >= workStart && endMinutes <= workEnd;
  if (!fits) continue;

  // ID do alternativo: usa o da agenda; se não houver, usa o do $input.first()
  const altAssignedId = cal.assigned_user_id || idFromInput || null;

  alternativas.push({
    assigned_user_id: altAssignedId,
    calendar_id: cal.calendar_id,
    calendar_name: cal.calendar_name,
    inicio: currentInicioISO,
    fim: currentFimISO,
  });
}

// Randomiza ordem dos alternativos
alternativas = shuffle(alternativas);

