  json: {
    // Corretor atual
    assigned_user_id_corretor_atual: atualAssignedId,
    calendar_id_corretor_atual: atualCalendarId,
    calendar_name_corretor_atual: atualCalendarName,
    inicio_corretor_atual: currentInicioISO,
    fim_corretor_atual: currentFimISO,

    // Corretor alternativo
    assigned_user_id_corretor_alternativo: alt.assigned_user_id,
    calendar_id_corretor_alternativo: alt.calendar_id,
    calendar_name_corretor_alternativo: alt.calendar_name,
    inicio_corretor_alternativo: alt.inicio,
    fim_corretor_alternativo: alt.fim,
  }
}));

if (!out.length){
  return [{
    json: {
      ok:false,
      motivo:'Nenhum corretor alternativo disponível nesse horário dentro do expediente.',
      data_e_hora: solicitadoRaw,
      assigned_user_id_corretor_atual: atualAssignedId,
      calendar_id_corretor_atual: atualCalendarId,
      calendar_name_corretor_atual: atualCalendarName,
      inicio_corretor_atual: currentInicioISO,
      fim_corretor_atual: currentFimISO
    }
  }];
}

return out;

