// Filtra dentro do plantão
const validos = candidatos.filter(({s,e}) => inside(s,e,plantaoStart,plantaoEnd));
validos.sort((a,b) => a.s - b.s);

// === Saída: cada opção é 1 item ===
return validos.map(({s,e}) => ({
  json: {
    calendar_id: row.calendar_id,
    inicio: makeLocalISO(s),
    fim: makeLocalISO(e),
    label: labelRange(s,e)
  }
}));

// Lê todos os itens de entrada
const items = $input.all();

// Extrai os horários disponíveis marcados como "true" (string ou boolean)
function coletarHorariosDisponiveis(items) {
  const slots = [];

  // Caso 1: veio um único item cujo .json é um array de objetos
  if (items.length === 1 && Array.isArray(items[0].json)) {
    for (const obj of items[0].json) {
      const [slot, val] = Object.entries(obj)[0] || [];
      if (val === true || val === "true") slots.push(slot);
    }
    return slots;
  }

  // Caso 2: veio como vários itens, cada um com um objeto { "13:00 - 14:00": "true" }
  for (const it of items) {
    const entries = Object.entries(it.json || {});
    if (entries.length === 1) {
      const [slot, val] = entries[0];
      if (val === true || val === "true") slots.push(slot);
    }
  }

  return slots;
}

const horariosDisponiveis = coletarHorariosDisponiveis(items);

// Tenta pegar o horário solicitado de outro nó (se existir)
let horarioSolicitado = null;
try {
  horarioSolicitado = $('Code').item.json.horario_solicitado || null;
} catch (e) {
  horarioSolicitado = null;
}

// Monta a mensagem
const prefixo = horarioSolicitado
  ? `Infelizmente no horário ${horarioSolicitado} não tenho disponibilidade.`
  : `Infelizmente não temos disponibilidade exatamente no horário solicitado.`;

let mensagem;
if (horariosDisponiveis.length > 0) {
  const lista = horariosDisponiveis.map(h => `• ${h}`).join('\n');
  mensagem = `${prefixo}\n\nPorém tenho disponibilidade nestes horários:\n${lista}\n\nMe diga qual você prefere que eu já agendo pra você.`;
} else {
  mensagem = `${prefixo}\n\nNo momento não há outras opções disponíveis. Quer que eu verifique outros dias ou turnos?`;
}

// Retorna um único item com a mensagem e a lista de horários
return [
  {
    json: {
      mensagem,
      horarios_disponiveis: horariosDisponiveis
    }
  }
];

// === Entrada ===
const dataEntrada = $('Webhook').first().json.body.data_e_hora;

// Converte para Date
const dateObj = new Date(dataEntrada);

// Função para formatar no padrão YYYY-MM-DDTHH:mm:ss-03:00
function formatISO(date) {
  const ano = date.getFullYear();
  const mes = String(date.getMonth() + 1).padStart(2, '0');
  const dia = String(date.getDate()).padStart(2, '0');
  const hora = String(date.getHours()).padStart(2, '0');
  const minuto = String(date.getMinutes()).padStart(2, '0');
  const segundo = String(date.getSeconds()).padStart(2, '0');
  return `${ano}-${mes}-${dia}T${hora}:${minuto}:${segundo}-03:00`;
}

// Data inicial (igual ao webhook)
const inicio = formatISO(dateObj);

// Data final (soma 1 hora, sem mexer no fuso)
const fimDate = new Date(dateObj.getTime() + 60 * 60 * 1000);
const fim = formatISO(fimDate);

// === Retorno ===
return [{
  json: {
    inicio,
    fim
  }
}];
